                system: if session.system_prompt().is_empty() {
                    None
                } else {
                    Some(session.system_prompt())
                },
                messages: session.history(),
                tools: &tool_specs,
                cache_hint: cfg.cache_hint,
                max_response_tokens: cfg.max_response_tokens,
            };

            let TurnResponse {
                content,
                stop_reason,
                usage,
                raw_request_body,
                raw_response_body,
