            drop((raw_request_body, raw_response_body, endpoint, http_status));

            if total_tokens_observed > cfg.max_total_tokens {
                return Err(AgentLoopError::TokenBudget {
                    limit: cfg.max_total_tokens,
                    observed: total_tokens_observed,
                });
