                    Ok(s) => s,
                    Err(err) => format!("{{\"error\":\"serialize: {err}\"}}"),
                };
                user_tool_results.push(ContentBlock::ToolResult {
                    tool_use_id,
                    content: tool_text,
                    is_error: outcome.is_error,
                });
            }

