                    _ => TerminateReason::Other,
                };
                return Ok(LoopOutcome {
                    final_message: last_text_reply,
                    usage: cumulative_usage,
                    terminate_reason,
                    trace,
                });
            }

            session.append_message(Message::user_blocks(user_tool_results));
        }
    }"}

